const body = $input.first().json.body || {};
const raw = body.message || JSON.stringify(body);

const lines = raw.split("\n").filter(l => l.trim());
const updated = lines.filter(l => l.includes("Updated") || l.includes("updated"));
const failed  = lines.filter(l => l.includes("Failed") || l.includes("failed") || l.includes("Error"));

const summary = lines.find(l => l.includes("Scanned") || l.includes("Session done")) || "";
const scanned = (summary.match(/Scanned=(\d+)/) || [])[1] || "?";
const updCount = (summary.match(/Updated=(\d+)/) || [])[1] || updated.length;
const failCount= (summary.match(/Failed=(\d+)/)  || [])[1] || failed.length;

let msg = `🐳 *Watchtower – Container Updates*\n\n`;
msg += `📦 Gescannt: ${scanned} | ✅ Aktualisiert: ${updCount} | ❌ Fehler: ${failCount}\n`;

if (updated.length > 0) {
  msg += `\n✅ *Aktualisiert:*\n`;
  updated.forEach(l => { msg += `• ${l.replace(/.*\//, "").replace(/["]/g, "").trim()}\n`; });
}
if (failed.length > 0) {
  msg += `\n❌ *Fehler:*\n`;
  failed.forEach(l => { msg += `• ${l.trim()}\n`; });
}

const now = new Date().toLocaleString("de-DE", {day:"2-digit",month:"2-digit",year:"numeric",hour:"2-digit",minute:"2-digit"});
msg += `\n🕐 ${now}`;

return [{ json: { message: msg } }];

